#if UNITY_EDITOR
using UnityEditor;
using UnityEngine;

/// <summary>
/// Editor customizado do EnemyController (Enemy Creator — Etapa 1.6).
///
/// - Inspector: desenha os campos normais e, para
///   <see cref="EnemyController.deactivationConditions"/>, usa
///   PolymorphicListDrawer (mesmo utilitário do NpcControllerEditor) para
///   listar/adicionar subclasses de EnemyCondition — vazio até à Etapa 5.4.
/// - Scene View: desenha gizmos editáveis (arrastáveis) para a área de
///   detecção (EnemyDetection — Etapa 1.4) e os pontos de patrulha
///   (EnemyMovement — Etapa 1.5), se esses componentes existirem no mesmo
///   GameObject.
/// </summary>
[CustomEditor(typeof(EnemyController))]
public class EnemyControllerEditor : Editor
{
    private SerializedProperty _deactivationConditionsProp;

    private void OnEnable()
    {
        _deactivationConditionsProp = serializedObject.FindProperty("deactivationConditions");
    }

    public override void OnInspectorGUI()
    {
        serializedObject.Update();

        DrawPropertiesExcluding(serializedObject, "m_Script", "deactivationConditions");

        EditorGUILayout.Space();
        PolymorphicListDrawer.Draw(serializedObject, _deactivationConditionsProp, "Condições de Desactivação (Etapa 5.4)", typeof(EnemyCondition), "Adicionar Condição de Desactivação");

        serializedObject.ApplyModifiedProperties();
    }

    private void OnSceneGUI()
    {
        var controller = (EnemyController)target;

        DrawDetectionHandles(controller);
        DrawPatrolHandles(controller);
        DrawAttackHandles(controller);
    }

    /// <summary>
    /// Handles para o alcance ("range") de cada ataque do EnemyAttackController
    /// (Etapa 7.2). Cada ataque tem o seu handle numa direcção ligeiramente
    /// diferente, com o nome do ataque como etiqueta, para não se sobreporem.
    /// </summary>
    private void DrawAttackHandles(EnemyController controller)
    {
        var attackController = controller.GetComponent<EnemyAttackController>();
        if (attackController == null || attackController.attacks == null) return;

        Vector3 origin = controller.transform.position;

        for (int i = 0; i < attackController.attacks.Count; i++)
        {
            var attack = attackController.attacks[i];
            if (attack == null) continue;

            // Espalha os handles: -30°, -50°, -70°, ... a partir da horizontal.
            float angle = (-30f - 20f * i) * Mathf.Deg2Rad;
            Vector3 dir = new Vector3(Mathf.Cos(angle), Mathf.Sin(angle), 0f);

            Handles.Label(origin + dir * attack.range, $"{attack.attackName} ({attack.range:0.0})");

            EditorGUI.BeginChangeCheck();
            float newRange = SizeHandle(origin, dir, attack.range, new Color(1f, 0.2f, 0.2f));
            if (EditorGUI.EndChangeCheck())
            {
                Undo.RecordObject(attackController, "Alterar Alcance do Ataque");
                attack.range = Mathf.Max(0f, newRange);
                EditorUtility.SetDirty(attackController);
            }

            if (attack.minRange > 0f)
            {
                EditorGUI.BeginChangeCheck();
                float newMin = SizeHandle(origin, dir, attack.minRange, new Color(1f, 0.6f, 0.1f));
                if (EditorGUI.EndChangeCheck())
                {
                    Undo.RecordObject(attackController, "Alterar Alcance Mínimo do Ataque");
                    attack.minRange = Mathf.Clamp(newMin, 0f, attack.range);
                    EditorUtility.SetDirty(attackController);
                }
            }
        }
    }

    /// <summary>Handles para o alcance de detecção (range) e o raio de proximidade (proximityRadius) do EnemyDetection, se presente.</summary>
    private void DrawDetectionHandles(EnemyController controller)
    {
        var detection = controller.GetComponent<EnemyDetection>();
        if (detection == null) return;

        Vector3 origin = controller.transform.position;

        if (detection.shape == DetectionShape.Circular || detection.shape == DetectionShape.ConeFrontal
            || detection.shape == DetectionShape.LinhaRecta || detection.shape == DetectionShape.AreaRectangular)
        {
            EditorGUI.BeginChangeCheck();
            float newRange = SizeHandle(origin, Vector3.right, detection.range, Color.cyan);
            if (EditorGUI.EndChangeCheck())
            {
                Undo.RecordObject(detection, "Alterar Alcance de Detecção");
                detection.range = Mathf.Max(0f, newRange);
            }
        }

        if (detection.proximityRadius > 0f)
        {
            EditorGUI.BeginChangeCheck();
            float newProx = SizeHandle(origin, Vector3.up, detection.proximityRadius, Color.yellow);
            if (EditorGUI.EndChangeCheck())
            {
                Undo.RecordObject(detection, "Alterar Raio de Proximidade");
                detection.proximityRadius = Mathf.Max(0f, newProx);
            }
        }
    }

    /// <summary>Desenha um handle arrastável a "dir * size" de "origin" e devolve a nova distância ao soltar.</summary>
    private float SizeHandle(Vector3 origin, Vector3 dir, float size, Color color)
    {
        Vector3 handlePos = origin + dir * size;

        var oldColor = Handles.color;
        Handles.color = color;

        float handleSize = HandleUtility.GetHandleSize(handlePos) * 0.1f;
        Vector3 newPos = Handles.FreeMoveHandle(handlePos, handleSize, Vector3.zero, Handles.SphereHandleCap);

        Handles.color = oldColor;

        return Vector3.Distance(origin, newPos);
    }

    /// <summary>Handles arrastáveis para cada ponto de patrulha do EnemyMovement, se presente.</summary>
    private void DrawPatrolHandles(EnemyController controller)
    {
        var movement = controller.GetComponent<EnemyMovement>();
        if (movement == null) return;
        if (movement.movementType == EnemyMovementType.Estatico) return;
        if (movement.patrolPoints == null) return;

        Vector3 basePos = Application.isPlaying ? controller.HomePosition : controller.transform.position;
        bool freeMovement = EnemyMovement.IsFreeMovementType(movement.movementType);

        Handles.color = Color.green;

        for (int i = 0; i < movement.patrolPoints.Count; i++)
        {
            Vector3 worldPos = basePos + (Vector3)movement.patrolPoints[i];

            EditorGUI.BeginChangeCheck();
            float size = HandleUtility.GetHandleSize(worldPos) * 0.12f;
            Vector3 newWorldPos = Handles.FreeMoveHandle(worldPos, size, Vector3.zero, Handles.CubeHandleCap);

            if (EditorGUI.EndChangeCheck())
            {
                Undo.RecordObject(movement, "Mover Ponto de Patrulha");

                Vector2 newOffset = (Vector2)(newWorldPos - basePos);
                if (!freeMovement)
                    newOffset.y = 0f;

                movement.patrolPoints[i] = newOffset;
            }
        }
    }
}
#endif
